import lxml.etree as ET
from defusedxml import ET

def process_soap_request(xml):
    # Parse the SOAP envelope and extract the message body
    root = ET.fromstring(xml)
    body = root.find(".//{http://schemas.xmlsoap.org/soap/envelope/}Body")
    
    # Validate the XML against the DTD
    dtd_file = "soap.dtd"
    with open(dtd_file, "r") as f:
        dtd = ET.DTD(f)
        dtd.validate(root)
    
    # Extract the message body content
    message = body.find(".//{http://www.example.com}message")
    return message.text